var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"결국 다른 사람들도 찾아가봤지만, 키울 여건이 마땅해 보이는 사람이 잘 없네.","JPN":"他の人にも当たってみたけど、ちょうどいい条件の人はいないね。","ENG":"We tried some other people, but none of them can afford a cat right now.","TWN":"結果還是沒找到合適養貓的人選…"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"네. 역시 완벽한 주인을 찾아주는 건 힘든 일인가봐요.","JPN":"はい。やっぱり完璧な里親さんを見つけるのは難しいですね。","ENG":"No, it's definitely not easy finding the perfect owner for him.","TWN":"對啊，要替牠找到完美主人真是不容易呢！"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"본래 완벽한 조건을 찾기란 존재하지 않는 법이다, 호진 대원.","JPN":"本来完璧に条件を満たす人など存在しないものだ、マユミ隊員。","ENG":"There's no such thing as perfection, Operative Hojin.","TWN":"鎬眞隊員，完美本來就不存在於這個世界上。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"전장의 상황이 항상 군인의 마음을 따라주지 않는 법.","JPN":"戦場の状況が、常に思いどおりにはいくとは限らない。","ENG":"The situation on the battlefield doesn't always go the way you want it.","TWN":"戰場上的事也是千變萬化，無法預測。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"중요한 건 그 상황에 자신이 어떻게 대처하느냐다. 모든 건 마음먹기에 달린 것이지.","JPN":"大事なのは、その状況に自分がどのように対処するかだ。\\nすべては気持ち次第である。","ENG":"You have to take it as it comes. Everything depends on your way of thinking.","TWN":"重點是，在那個當下你會如何反應，關鍵在於你的決心。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"와, 소림아. 너 엄청 굉장하다.","JPN":"わあ、ミズキちゃん……カッコいい。","ENG":"Whoa, Sorim! That sounds incredible!","TWN":"哇～蕭林，你竟然能說出這種大道理。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"훗, 본관은 베테랑. 이런 지혜 또한 산전수전을 거친 경험의 산물이라고 할 수 있다.","JPN":"フフッ、本官はベテランだ。\\nこのような知恵もまた、長年にわたる豊富な経験の産物と言えるだろう。","ENG":"Heh. I'm a veteran. I've gained such wisdom during years of hardship I've gone through.","TWN":"哼哼，本官好歹也是征戰無數的沙場老將，當然也累積不少人生智慧跟經驗。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"똑똑한 소림이 말이 맞아. 우리가 너무 먼 곳에서 답을 찾으려고 했던 것 같아.","JPN":"ミズキちゃんの言う通りだよ。私たちは考えすぎて、\\n手の届かないところで答えを探そうとしていたのかもしれない。","ENG":"I agree with smart Sorim. Perhaps we were looking too far away for the answer.","TWN":"有智慧的蕭林說的沒錯！我們有點本末倒置了。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"호, 호진 언니. 그렇게까지 칭찬하면 부끄러운데……","JPN":"そ、そんなに褒められると照れてしまう……","ENG":"H-Hojin, you flatter me so much...","TWN":"鎬…鎬眞姐，你這樣一直誇我，我會害羞……"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"고양이가 키워질 환경이나 주인 같은 건 중요하지 않아!","JPN":"猫を飼う環境や飼い主より、大事なものがあります！","ENG":"It doesn't matter what kind of environment the cat will be raised in or who will raise him.","TWN":"養貓的重點不是環境或主人！"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"맞아요. 환경보다 중요한 건, 마음이죠!","JPN":"そうです。環境より大事なのは、気持ちです！","ENG":"No. What matters more than the environment is the heart.","TWN":"沒錯！比起那些，更重要的是心！"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L16_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"응! 이제 더는 조건을 따지지 말고 고양이와 마음이 통하는 사람을 찾아보자!","JPN":"うん！　もう条件より、猫ちゃんと心が通じる人を探そう！","ENG":"That's right! Let's stop being so picky and find someone who can really love Maximus.","TWN":"沒錯！我們就放棄那些所謂的條件，找個能和貓咪合得來的人吧！"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"하지만 여전히 문제가 있다. 그런 사람을 어디서 찾지?","JPN":"しかしまだ問題がある。どこで探せばいいんだ？","ENG":"But here's the problem: where can we find them?","TWN":"但還是有問題欸？那種人要去哪找？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"우리가 키우면 돼! 어떻게든 비용을 마련해서 고양이가 따로 지낼 수 있는 공간을 마련해보자.","JPN":"私たちが飼えばいいの！\\nなんとかお金を用意して、猫ちゃんが過ごせる場所を用意してみよう。","ENG":"We don't have to. We can raise him. We'll get money, somehow, to create a separate place for him in the clubhouse.","TWN":"不用找了，就是我們！我們就想辦法弄點經費幫貓咪弄個家吧！"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"<color=#ffd34c>막시무스</color>가 우릴 부담스러워하지만 않는다면 말이야.","JPN":"<color=#ffd34c>マクシムス</color>が私たちでもよければの話だけど。","ENG":"If <color=#ffd34c>Maximus</color> wants to stay with us, that is.","TWN":"只要<color=#ffd34c>咖啡貓</color>不討厭我們的話！"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"……응.","JPN":"……うん。","ENG":"... Okay.","TWN":"……嗯。"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"자! 그럼 이제 아카데미로 돌아가서 새 동료를 받아들일 준비를……","JPN":"さて！　アカデミーに戻って新しい家族を迎え入れる準備を……","ENG":"Alright, then let's go back to the Academy and get ready for our new companion—","TWN":"既然都決定好了，我們就回去學院開始新夥伴入住的準備工作吧……"},"stage":{"bg":"CITY_CENTER1","slots":{"L":null,"C":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"어라?","JPN":"あれ？","ENG":"Err?","TWN":"嗯？"},"stage":{"bg":"CITY_CENTER1","slots":{"L":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"}}}}]`);export{e as default};